const sd = $getWorkflowStaticData('global');
const resp = $input.first().json;
if (!sd.qStarted) { sd.qAll = []; sd.qStarted = true; sd.qPages = 0; sd.qCursor = null; }
const throttled = resp && resp.errors && resp.errors.some(e => e && e.extensions && e.extensions.code === 'THROTTLED');
if (throttled) { await new Promise(r => setTimeout(r, 2500)); return [{ done: false, cursor: sd.qCursor }]; }
const conn = (resp && resp.data && resp.data.quotes) ? resp.data.quotes : null;
if (conn) {
  sd.qAll = sd.qAll.concat(conn.nodes || []);
  sd.qPages = (sd.qPages || 0) + 1;
  const pi = conn.pageInfo || {};
  if (pi.hasNextPage && pi.endCursor && sd.qPages < 100) { sd.qCursor = pi.endCursor; return [{ done: false, cursor: pi.endCursor }]; }
}
sd.qStarted = false;
return [{ done: true, count: (sd.qAll || []).length }];

