// ============================================================
// Build the dashboard payload. Jobber records come from the
// pagination loops (workflow static data). QB comes from the
// QB nodes (may be empty until production keys are connected).
// ============================================================
const sd = $getWorkflowStaticData('global');

function dedupe(arr, idKey) {
  const seen = new Set();
  const out = [];
  for (const x of (arr || [])) {
    const k = x && x[idKey];
    if (k == null) { out.push(x); continue; }
    if (seen.has(k)) continue;
    seen.add(k); out.push(x);
  }
  return out;
}

function flattenQB(nodeName, entity) {
  let out = [];
  try {
    for (const item of $(nodeName).all()) {
      const rows = item.json && item.json.QueryResponse && item.json.QueryResponse[entity] || [];
      out = out.concat(rows);
    }
  } catch (e) { return []; }
  return out;
}

const quotes = dedupe(sd.qAll || [], 'id');
const requests = dedupe(sd.rAll || [], 'id');
const clients = dedupe(sd.cAll || [], 'id');
const qbInvoices = dedupe(flattenQB('QB Invoices', 'Invoice'), 'Id');
const qbPayments = dedupe(flattenQB('QB Payments', 'Payment'), 'Id');

const now = new Date();
const year = now.getFullYear();
const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const months = MONTH_NAMES.slice(0, now.getMonth() + 1);

function monthOf(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  // Bucket by the company's local time (Victoria BC) to match Jobber's reports.
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'America/Vancouver', year: 'numeric', month: 'numeric' }).formatToParts(d);
  const y = Number(parts.find(p => p.type === 'year').value);
  const m = Number(parts.find(p => p.type === 'month').value);
  if (y !== year) return null;
  return MONTH_NAMES[m - 1];
}
function emptyMonths() { const o = {}; months.forEach(m => { o[m] = 0; }); return o; }

// Use each quote's real salesperson name (matches Jobber's Salesperson Performance report person-for-person).
function personOf(quote) {
  return (quote.salesperson && quote.salesperson.name && quote.salesperson.name.full || '').trim() || 'Unassigned';
}
function ensurePerson(obj, person) { if (!obj[person]) obj[person] = emptyMonths(); return obj[person]; }

const revenueProduced = emptyMonths();
for (const inv of qbInvoices) { const mo = monthOf(inv.TxnDate); if (mo && months.includes(mo)) revenueProduced[mo] += parseFloat(inv.TotalAmt) || 0; }

const cashCollected = emptyMonths();
for (const p of qbPayments) { const mo = monthOf(p.TxnDate); if (mo && months.includes(mo)) cashCollected[mo] += parseFloat(p.TotalAmt) || 0; }

const newLeads = emptyMonths();
for (const c of clients) { const mo = monthOf(c.createdAt); if (mo && months.includes(mo)) newLeads[mo] += 1; }

const newRequests = emptyMonths();
for (const r of requests) { const mo = monthOf(r.createdAt); if (mo && months.includes(mo)) newRequests[mo] += 1; }

const quotesSentTotal = emptyMonths();
const quotesSentByPerson = {};
const quotesConvertedTotal = emptyMonths();
const quotesConvertedByPerson = {};
const convertedDollarsTotal = emptyMonths();
const convertedDollarsByPerson = {};
const SENT = new Set(['AWAITING_RESPONSE','CHANGES_REQUESTED','APPROVED','CONVERTED','ARCHIVED']);

for (const q of quotes) {
  const status = (q.quoteStatus || '').toUpperCase();
  const person = personOf(q);
  const amount = parseFloat(q.amounts && q.amounts.total) || 0;
  // Quotes Sent = "Sent within" the month (by sentAt) — matches Jobber's Quotes report (Sent within filter).
  const sentMo = monthOf(q.sentAt);
  if (sentMo && months.includes(sentMo)) { quotesSentTotal[sentMo] += 1; ensurePerson(quotesSentByPerson, person)[sentMo] += 1; }
  // Quotes Converted + $ = "Converted within" the month (by transitionedAt) — matches Jobber's Quotes report (Converted within filter).
  if (status === 'CONVERTED') {
    const convMo = monthOf(q.transitionedAt);
    if (convMo && months.includes(convMo)) {
      quotesConvertedTotal[convMo] += 1;
      ensurePerson(quotesConvertedByPerson, person)[convMo] += 1;
      convertedDollarsTotal[convMo] += amount;
      ensurePerson(convertedDollarsByPerson, person)[convMo] += amount;
    }
  }
}

function round2(map) { for (const k of Object.keys(map)) map[k] = Math.round(map[k] * 100) / 100; return map; }
round2(revenueProduced); round2(cashCollected); round2(convertedDollarsTotal);

// Unify the salesperson set across sent + converted so every rep exists in all maps.
const allPersons = Array.from(new Set(Object.keys(quotesSentByPerson).concat(Object.keys(quotesConvertedByPerson))));
for (const p of allPersons) { ensurePerson(quotesSentByPerson, p); ensurePerson(quotesConvertedByPerson, p); ensurePerson(convertedDollarsByPerson, p); }
for (const p of allPersons) round2(convertedDollarsByPerson[p]);

function rate(conv, sent) { const o = {}; for (const m of months) o[m] = (sent[m] || 0) > 0 ? Math.round((conv[m] / sent[m]) * 1000) / 10 : 0; return o; }
const conversionRateTotal = rate(quotesConvertedTotal, quotesSentTotal);
const conversionRateByPerson = {};
for (const p of allPersons) conversionRateByPerson[p] = rate(quotesConvertedByPerson[p], quotesSentByPerson[p]);

function avg(dollars, conv) { const o = {}; for (const m of months) o[m] = (conv[m] || 0) > 0 ? Math.round((dollars[m] / conv[m]) * 100) / 100 : 0; return o; }
const avgSaleTotal = avg(convertedDollarsTotal, quotesConvertedTotal);
const avgSaleByPerson = {};
for (const p of allPersons) avgSaleByPerson[p] = avg(convertedDollarsByPerson[p], quotesConvertedByPerson[p]);

return [{
  months,
  revenueProduced, cashCollected, newLeads, newRequests,
  quotesSent: { total: quotesSentTotal, byPerson: quotesSentByPerson },
  quotesConverted: { total: quotesConvertedTotal, byPerson: quotesConvertedByPerson },
  conversionRate: { total: conversionRateTotal, byPerson: conversionRateByPerson },
  convertedDollars: { total: convertedDollarsTotal, byPerson: convertedDollarsByPerson },
  avgSale: { total: avgSaleTotal, byPerson: avgSaleByPerson },
  _debug: { quotes: quotes.length, requests: requests.length, clients: clients.length, invoices: qbInvoices.length, payments: qbPayments.length }
}];
